module shift_register(clk, din, q);

    input clk;
    input din;
    output [3:0] q;
    reg [3:0] q;
    initial q = 0;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
        begin
            q <= {din, q[3:1]};
        end

endmodule
